import { useState } from "react";

function percent(value) {
  return `${(value * 100).toFixed(2)}%`;
}

function App() {
  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [result, setResult] = useState(null);

  async function handleScan() {
    if (!url.trim()) {
      setError("Enter a URL before scanning.");
      return;
    }

    setLoading(true);
    setError("");
    setResult(null);

    try {
      const response = await fetch(`/api/scan`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url: url.trim() })
      });

      if (!response.ok) {
        const payload = await response.json().catch(() => ({}));
        throw new Error(payload.detail || "Scan failed");
      }

      const payload = await response.json();
      setResult(payload);
    } catch (err) {
      setError(err.message || "Unable to connect to backend API.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="page">
      <main className="container">
        <h1>Phishing Checker</h1>
        <p className="subtitle">Paste a URL and scan it.</p>

        <div className="input-group">
          <input
            value={url}
            onChange={(e) => setUrl(e.target.value)}
            placeholder="https://example.com"
          />
          <button onClick={handleScan} disabled={loading}>
            {loading ? "Scanning..." : "Scan"}
          </button>
        </div>

        {error && <p className="error">{error}</p>}

        {result && (
          <section className="result">
            <div className="summary">
              <div>
                <span className="label">Result</span>
                <strong className={`status ${result.prediction}`}>
                  {result.prediction.toUpperCase()}
                </strong>
              </div>
              <div>
                <span className="label">Confidence</span>
                <strong>{percent(result.confidence)}</strong>
              </div>
              <div>
                <span className="label">Risk</span>
                <strong>{percent(result.risk_score)}</strong>
              </div>
            </div>

            <div className="details">
              <h2>Top features</h2>
              <ul>
                {result.top_features.map((item) => (
                  <li key={item.feature}>
                    <span>{item.feature}</span>
                    <strong>{item.shap_value.toFixed(4)}</strong>
                  </li>
                ))}
              </ul>
            </div>

            <div className="details">
              <h2>Explanation chart</h2>
              <img
                src={`data:image/png;base64,${result.shap_plot_base64}`}
                alt="SHAP chart"
              />
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

export default App;

